import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const p=JSON.parse('{"title":"Ultimate Security & Trust Boundary Doctrine","description":"Mandatory rules for secrets, auth, permissions, operator trust, and fail-closed behavior.","frontmatter":{"title":"Ultimate Security & Trust Boundary Doctrine","description":"Mandatory rules for secrets, auth, permissions, operator trust, and fail-closed behavior."},"headers":[],"relativePath":"best-practices/security.md","filePath":"best-practices/security.md"}'),s={name:"best-practices/security.md"};function l(o,e,n,u,c,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ultimate-security-trust-boundary-doctrine" tabindex="-1">Ultimate Security &amp; Trust Boundary Doctrine <a class="header-anchor" href="#ultimate-security-trust-boundary-doctrine" aria-label="Permalink to &quot;Ultimate Security &amp; Trust Boundary Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> Security in OpenSIN is not a checklist item. It is the discipline of deciding what the system is allowed to trust, what it is never allowed to expose, and how it must fail when trust is uncertain.</p></blockquote><hr><h2 id="_1-trust-boundaries-must-be-explicit" tabindex="-1">1. Trust Boundaries Must Be Explicit <a class="header-anchor" href="#_1-trust-boundaries-must-be-explicit" aria-label="Permalink to &quot;1. Trust Boundaries Must Be Explicit&quot;">​</a></h2><p>Every system must know:</p><ul><li>what input is trusted</li><li>what input is untrusted</li><li>what credentials it may access</li><li>what side effects require confirmation</li><li>what should fail closed instead of fail open</li></ul><p>If these boundaries are implicit, they will be violated.</p><hr><h2 id="_2-secret-handling-rules" tabindex="-1">2. Secret Handling Rules <a class="header-anchor" href="#_2-secret-handling-rules" aria-label="Permalink to &quot;2. Secret Handling Rules&quot;">​</a></h2><h3 id="never-do" tabindex="-1">Never do <a class="header-anchor" href="#never-do" aria-label="Permalink to &quot;Never do&quot;">​</a></h3><ul><li>hardcode secrets</li><li>commit secrets</li><li>print secrets in logs</li><li>pass secrets through screenshots or issue bodies</li><li>leave secrets in temporary scripts or throwaway files</li></ul><h3 id="always-do" tabindex="-1">Always do <a class="header-anchor" href="#always-do" aria-label="Permalink to &quot;Always do&quot;">​</a></h3><ul><li>keep secrets in env vars / credential stores / approved secret surfaces</li><li>redact logs</li><li>rotate leaked tokens immediately</li><li>prefer least privilege</li></ul><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>A leaked secret is not “just a mistake.” It is an attacker invitation.</p><hr><h2 id="_3-confirmation-gates" tabindex="-1">3. Confirmation Gates <a class="header-anchor" href="#_3-confirmation-gates" aria-label="Permalink to &quot;3. Confirmation Gates&quot;">​</a></h2><p>Actions that are destructive, security-sensitive, identity-sensitive, or billing-sensitive require explicit confirmation unless the operator has clearly delegated that authority.</p><p>Examples:</p><ul><li>deleting data</li><li>rotating production credentials</li><li>changing auth rules</li><li>binding domains</li><li>making billing-affecting API changes</li></ul><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Autonomy without permission gates becomes self-sabotage.</p><hr><h2 id="_4-fail-closed-by-default" tabindex="-1">4. Fail-Closed by Default <a class="header-anchor" href="#_4-fail-closed-by-default" aria-label="Permalink to &quot;4. Fail-Closed by Default&quot;">​</a></h2><p>When validation is missing, signatures are absent, auth is unclear, or required config is incomplete, the system must refuse activation.</p><h3 id="why-2" tabindex="-1">Why <a class="header-anchor" href="#why-2" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Fail-open behavior turns uncertainty into compromise.</p><hr><h2 id="_5-scope-least-privilege" tabindex="-1">5. Scope &amp; Least Privilege <a class="header-anchor" href="#_5-scope-least-privilege" aria-label="Permalink to &quot;5. Scope &amp; Least Privilege&quot;">​</a></h2><p>Every token, credential, and integration should have only the permissions it actually needs.</p><h3 id="anti-patterns" tabindex="-1">Anti-patterns <a class="header-anchor" href="#anti-patterns" aria-label="Permalink to &quot;Anti-patterns&quot;">​</a></h3><ul><li>one global god-token for everything</li><li>sharing admin credentials across unrelated agents</li><li>reusing powerful tokens in docs/tests/examples</li></ul><hr><h2 id="_6-security-logging" tabindex="-1">6. Security Logging <a class="header-anchor" href="#_6-security-logging" aria-label="Permalink to &quot;6. Security Logging&quot;">​</a></h2><p>Security-relevant events must be visible without exposing the secret itself:</p><ul><li>auth failures</li><li>permission denials</li><li>suspicious retries</li><li>unexpected environment mismatch</li><li>token rotation events</li></ul><p>Log the event, not the credential.</p><hr><h2 id="_7-browser-ui-security-implications" tabindex="-1">7. Browser / UI Security Implications <a class="header-anchor" href="#_7-browser-ui-security-implications" aria-label="Permalink to &quot;7. Browser / UI Security Implications&quot;">​</a></h2><p>Browser automation often crosses powerful trust boundaries:</p><ul><li>admin consoles</li><li>OAuth approvals</li><li>dashboards with billing power</li></ul><p>Therefore profile selection, permissions, and evidence capture are part of security, not just convenience.</p><hr><h2 id="_8-documentation-security-rule" tabindex="-1">8. Documentation Security Rule <a class="header-anchor" href="#_8-documentation-security-rule" aria-label="Permalink to &quot;8. Documentation Security Rule&quot;">​</a></h2><p>Docs may explain secret flow, but must not contain real secrets, token-shaped values, or copy-pasteable privileged credentials.</p><h3 id="why-3" tabindex="-1">Why <a class="header-anchor" href="#why-3" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>A markdown file in Git is forever unless cleaned aggressively.</p><hr><h2 id="_9-final-rule" tabindex="-1">9. Final Rule <a class="header-anchor" href="#_9-final-rule" aria-label="Permalink to &quot;9. Final Rule&quot;">​</a></h2><p><strong>Security is the discipline of protecting trust, not the performance of looking careful.</strong> If the system cannot explain why it trusts an action, it should not perform it.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p>',52)])])}const m=t(s,[["render",l]]);export{p as __pageData,m as default};
